// Build a compact prompt for Haiku — the goal is *patterns*, not raw
// failure counts. Capped at 2KB output so Master Router can prepend it
// to AI worker system prompts without blowing context budgets.
const rows = $input.all().map(i => i.json);
if (rows.length === 0) {
  return [{ json: { skip: true, reason: 'no failures in last 24h' } }];
}

const lines = rows.slice(0, 25).map(r => {
  const reasonings = (r.reasonings || []).filter(x => x).slice(0, 3)
    .map(s => String(s).slice(0, 200)).join(' | ');
  const errs = (r.error_msgs || []).filter(x => x).slice(0, 2)
    .map(s => String(s).slice(0, 200)).join(' | ');
  return `${r.pipeline} (${r.result}, ${r.occurrences}x, worker=${r.ai_worker || 'n/a'}): ` +
         (reasonings || errs || '(no detail)');
});

const input = lines.join('\n');

const sys = `You distil 24 hours of pipeline failures into ≤8 short heuristics that a future AI worker can apply to avoid repeating the failure. Output is read by AI workers as part of their system prompt.

Rules:
- Each heuristic is a single sentence, ≤140 chars, imperative voice.
- Mention the specific pattern (e.g. "Treat St Austell Brewery invoices over £2000 as anomalous — flag for human review").
- Skip generic advice. Skip apologies.
- If the failures are too noisy or generic to extract patterns, return an empty list.

Return ONLY a JSON array of strings, max 8 entries.`;

return [{
  json: {
    skip: false,
    raw_failures: input,
    prompt_system: sys,
    failure_count: rows.length
  }
}];

// Parse Haiku JSON array → markdown bullets, capped at 2KB.
const item = $input.first().json;
let heuristics = [];
try {
  let text = item.content?.[0]?.text || '[]';
  if (text.startsWith('```')) text = text.replace(/^```[a-z]*\n?/, '').replace(/```\s*$/, '').trim();
  heuristics = JSON.parse(text);
  if (!Array.isArray(heuristics)) heuristics = [];
} catch (e) {
  heuristics = [];
}
heuristics = heuristics.filter(h => typeof h === 'string' && h.trim().length > 0).slice(0, 8);

const now = new Date().toISOString();
const failureCount = $('Build Dreaming Prompt').first().json.failure_count;

let md = `# Heuristics — Dreaming Workflow H\n\n` +
         `Auto-generated nightly by \`dreaming-v1\`. Do not hand-edit —\n` +
         `your edits are overwritten on the next 02:00 run.\n\n` +
         `Master Router reads this file at start-of-batch (capped at 2KB)\n` +
         `and prepends the most recent entries to AI worker system prompts.\n\n` +
         `Generated: ${now}\n` +
         `Source: ${failureCount} failure groups in audit_log over last 24h\n\n` +
         `---\n\n`;

if (heuristics.length === 0) {
  md += '_(Haiku found no actionable patterns from this run — quiet day or noisy failures.)_\n';
} else {
  md += heuristics.map(h => `- ${h}`).join('\n') + '\n';
}

// Cap whole file at 2KB so Master Router can paste it cheaply
const FILE_CAP = 2048;
if (md.length > FILE_CAP) md = md.slice(0, FILE_CAP - 1) + '…';

return [{
  json: {
    file_path: '/data/storage/dreaming/heuristics.md',
    content: md,
    heuristics_count: heuristics.length,
    failure_count: failureCount,
  },
  binary: { data: { data: Buffer.from(md, 'utf8').toString('base64'),
                    fileName: 'heuristics.md', mimeType: 'text/markdown' } }
}];
